import time

def timer(func):
  def wrapper(*args, **kwargs):
    start = time.time()
    result = func(*args, **kwargs)
    end = time.time()
    print(f'Time taken: {end - start}')
    return result
  return wrapper

@timer
def slow_add(a, b):
  time.sleep(0.1)
  return a + b
